// -------------------------------------------------------------------------
// PROJECT RUNTIME AGGREGATOR
// -------------------------------------------------------------------------
// Source data lives in `src/data/projectSources.js`.
// Derived runtime media is generated by `scripts/generate-project-media.mjs`.
// -------------------------------------------------------------------------

import projectMediaManifest from './generated/projectMediaManifest.json';
import { projectSources } from './projectSources.js';

function getRuntimeMedia(project) {
    const derived = projectMediaManifest[String(project.id)] || {};
    const fallbackPoster = project.thumbnail || null;
    const fallbackVideo = project.videoSource || null;

    return {
        poster: derived.poster || fallbackPoster,
        cardPreview: derived.cardPreview || fallbackVideo,
        modalVideo: derived.modalVideo || fallbackVideo,
        masterVideo: fallbackVideo,
    };
}

export const projects = projectSources.map((project) => {
    const media = getRuntimeMedia(project);

    return {
        ...project,
        media,
        thumbnail: media.poster || project.thumbnail,
    };
});
